53	const PROCESSING_FEE = 5;
54	
55	const ITEM_BASE_PREMIUM: Record<string, number> = {
56	  sword: 100,
57	  amulet: 60,
58	  staff: 80,
59	  potion: 40,
60	  rune: 25,
61	  moonstone: 25,
62	};
63	
64	const basePremiumFor = (item: Item): number => ITEM_BASE_PREMIUM[item.type];
65	
66	const COMPONENT_BLOCK_PREMIUM = 60;
67	
68	const sumBasePremiums = (items: Item[]): number =>
69	  items.reduce((sum, item) => sum + basePremiumFor(item), 0);
70	
71	const COMPONENT_TYPES = ["rune", "moonstone"];
72	
73	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
74	
75	const componentGroupTotal = (group: Item[]): number =>
76	  group.length === 3 ? COMPONENT_BLOCK_PREMIUM : sumBasePremiums(group);
77	
78	const componentsTotal = (items: Item[]): number =>
79	  COMPONENT_TYPES.reduce(
80	    (sum, type) => sum + componentGroupTotal(items.filter((i) => i.type === type)),
81	    0,
82	  );
83	
84	const itemsBaseTotal = (items: Item[]): number =>
85	  sumBasePremiums(items.filter((i) => !isComponent(i))) + componentsTotal(items);
86	
87	const CURSE_SURCHARGE_RATE = 0.5;
88	const HIGH_ENCHANTMENT_THRESHOLD = 5;
89	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
90	
91	const isCursed = (item: Item): boolean => item.cursed === true;
92	const isHighlyEnchanted = (item: Item): boolean =>
93	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
94	
95	const ITEM_SURCHARGE_RATES: ReadonlyArray<(item: Item) => number> = [
96	  (item) => (isCursed(item) ? CURSE_SURCHARGE_RATE : 0),
97	  (item) => (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0),
98	];
99	
100	const itemSurchargeRate = (item: Item): number =>
101	  ITEM_SURCHARGE_RATES.reduce((sum, rate) => sum + rate(item), 0);
102	
103	const itemSurcharges = (items: Item[]): number =>
104	  items.reduce((sum, item) => sum + basePremiumFor(item) * itemSurchargeRate(item), 0);
105	
106	const LOYALTY_THRESHOLD_YEARS = 2;
107	const LOYALTY_DISCOUNT_RATE = 0.2;
108	
109	const policyDiscountRate = (customer: Customer): number =>
110	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT_RATE : 0;
111	
112	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
113	
114	const isNewcomer = (customer: Customer): boolean => customer.yearsWithMHPCO === 0;
115	
116	const firstInsuranceSurcharge = (items: Item[], customer: Customer): number =>
117	  isNewcomer(customer) ? itemsBaseTotal(items) * FIRST_INSURANCE_SURCHARGE_RATE : 0;
118	
119	const quote = ({ items }: QuoteStep, customer: Customer): QuoteResult => ({
120	  premium:
121	    itemsBaseTotal(items) * (1 - policyDiscountRate(customer)) +
122	    itemSurcharges(items) +
123	    firstInsuranceSurcharge(items, customer) +
124	    PROCESSING_FEE,
125	});
126	
127	export const runScenario = (scenario: Scenario): ScenarioResult => ({
128	  results: scenario.steps.map((step) =>
129	    step.op === "quote" ? quote(step, scenario.customer) : { payout: 0, remainingCap: 0 },
130	  ),
131	});
